import { render, route } from "rwsdk/router";
import { defineApp } from "rwsdk/worker";

import { Document } from "@/app/document";
import { setCommonHeaders } from "@/app/headers";
import { Home } from "@/app/pages/home";
import { About } from "@/app/pages/about";
import { UserProfile } from "@/app/pages/userProfile";

export type AppContext = {};

const app = defineApp([
  setCommonHeaders(),
  ({ ctx }) => {
    // setup ctx here
    ctx;
  },
  render(Document, [
    route("/home", Home),
    route("/about", About),
    route("/users/:id", UserProfile),
  ]),
]);

export default app;

import { linkFor } from "rwsdk/router";
import type app from "@/worker";

export const link = linkFor<typeof app>();

import { link } from "@/app/shared/links";

export const About = () => {
  return (
    <div>
      <h1>About</h1>
      <a href={link("/home")}>Back to home</a>
    </div>
  );
};

import { RequestInfo } from "rwsdk/worker";

export const UserProfile = ({ params }: RequestInfo) => {
  return (
    <div>
      <p>User profile: {params.id}</p>
    </div>
  );
};

import { link } from "@/app/shared/links";

export const Home = () => {
  return (
    <div>
      <h1>Home</h1>
      <a href={link("/about")}>About</a>
      <a href={link("/users/:id", { id: "42" })}>Show user 42</a>
    </div>
  );
};

